// ======================
// IMPORTS
// ======================
import "./index.css";
import { initialCards } from "../utils/constants.js";

import avatarImage from "../images/spots-images/avatar.jpg";
import logoImage from "../images/spots-images/Logo.svg";
import editIconImage from "../images/spots-images/editIcon.svg";
import addIconImage from "../images/spots-images/addIcon.svg";

// ======================
// DOM ELEMENTS
// ======================
const profileNameElement = document.querySelector(".profile__name");
const profileJobElement = document.querySelector(".profile__description");
const profileAvatar = document.querySelector(".profile__avatar");

const editButton = document.querySelector(".profile__edit-btn");
const addButton = document.querySelector(".profile__add-btn");

const editModal = document.querySelector("#edit-profile-modal");
const addModal = document.querySelector("#new-post-modal");
const previewModal = document.querySelector("#preview-modal");
const avatarModal = document.querySelector("#edit-avatar-modal");
const deleteModal = document.querySelector("#confirm-delete-modal");

const profileForm = document.querySelector("#profile-form");
const addForm = document.querySelector("#add-card-form");
const avatarForm = document.querySelector("#avatar-form");
const deleteForm = document.querySelector("#delete-form");

const nameInput = document.querySelector("#profile-name-input");
const jobInput = document.querySelector("#profile-description-input");

const cardTitleInput = document.querySelector("#card-title-input");
const cardLinkInput = document.querySelector("#card-link-input");

const avatarInput = document.querySelector("#avatar-input");

const cardsContainer = document.querySelector(".cards__list");
const cardTemplate = document.querySelector("#card-template").content;

// ======================
// STATIC IMAGES
// ======================
document.querySelector(".header__logo").src = logoImage;
document.querySelector(".profile__edit-btn img").src = editIconImage;
document.querySelector(".profile__add-btn img").src = addIconImage;
profileAvatar.src = avatarImage;

// ======================
// MODAL FUNCTIONS
// ======================
function openModal(modal) {
  modal.classList.add("modal_is-opened");
}

function closeModal(modal) {
  modal.classList.remove("modal_is-opened");
}

// overlay close
document.querySelectorAll(".modal").forEach((modal) => {
  modal.addEventListener("mousedown", (evt) => {
    if (evt.target === modal) closeModal(modal);
  });
});

// close buttons
document.querySelectorAll(".modal__close-btn").forEach((btn) => {
  const modal = btn.closest(".modal");
  btn.addEventListener("click", () => closeModal(modal));
});

// ======================
// CARD CREATION
// ======================
let selectedCard = null;

function createCard(data) {
  const cardElement = cardTemplate.cloneNode(true);
  const card = cardElement.querySelector(".card");

  const image = card.querySelector(".card__image");
  const title = card.querySelector(".card__title");
  const deleteBtn = card.querySelector(".card__delete-btn");
  const likeBtn = card.querySelector(".card__like-btn");

  image.src = data.link;
  image.alt = data.name;
  title.textContent = data.name;

  // preview modal
  image.addEventListener("click", () => {
    previewModal.querySelector(".modal__image").src = data.link;
    previewModal.querySelector(".modal__image").alt = data.name;
    previewModal.querySelector(".modal__caption").textContent = data.name;
    openModal(previewModal);
  });

  // delete modal
  deleteBtn.addEventListener("click", () => {
    selectedCard = card;
    openModal(deleteModal);
  });

  // like toggle
  likeBtn.addEventListener("click", () => {
    likeBtn.classList.toggle("card__like-btn_active");
  });

  return card;
}

function renderCard(data) {
  const card = createCard(data);
  cardsContainer.prepend(card);
}

// ======================
// EDIT PROFILE (PLACEHOLDERS STAY)
// ======================
editButton.addEventListener("click", () => {
  profileForm.reset(); // 🔥 keeps placeholders visible
  openModal(editModal);
});

profileForm.addEventListener("submit", (evt) => {
  evt.preventDefault();

  profileNameElement.textContent = nameInput.value;
  profileJobElement.textContent = jobInput.value;

  closeModal(editModal);
});

// ======================
// ADD CARD
// ======================
addButton.addEventListener("click", () => {
  addForm.reset();
  openModal(addModal);
});

addForm.addEventListener("submit", (evt) => {
  evt.preventDefault();

  const newCard = {
    name: cardTitleInput.value,
    link: cardLinkInput.value,
  };

  renderCard(newCard);
  addForm.reset();
  closeModal(addModal);
});

// ======================
// DELETE CARD
// ======================
const cancelBtn = deleteModal.querySelector(".modal__cancel-btn");

cancelBtn.addEventListener("click", () => {
  closeModal(deleteModal);
});

deleteForm.addEventListener("submit", (evt) => {
  evt.preventDefault();

  if (selectedCard) {
    selectedCard.remove();
    selectedCard = null;
  }

  closeModal(deleteModal);
});

// ======================
// AVATAR
// ======================
profileAvatar.addEventListener("click", () => {
  avatarForm.reset();
  openModal(avatarModal);
});

avatarForm.addEventListener("submit", (evt) => {
  evt.preventDefault();

  profileAvatar.src = avatarInput.value;

  avatarForm.reset();
  closeModal(avatarModal);
});

// ======================
// INITIAL CARDS
// ======================
initialCards.forEach(renderCard);
